package store

import (
	"fmt"
	"os"
	"sync"

	"github.com/volcano-sh/agentcube/pkg/store/redis"
	"github.com/volcano-sh/agentcube/pkg/store/valkey"
	"k8s.io/klog/v2"
)

var (
	storeInstance Store
	storeOnce     sync.Once
	storeErr      error
)

func Storage() Store {
	storeOnce.Do(func() {
		storeType := getEnv("STORE_TYPE", "redis")

		switch storeType {
		case "redis":
			storeInstance, storeErr = newRedisStore()
		case "valkey":
			storeInstance, storeErr = newValkeyStore()
		default:
			storeErr = fmt.Errorf("unsupported store type: %s (supported: redis, valkey)", storeType)
		}

		if storeErr != nil {
			klog.Fatal(storeErr)
		}
	})

	return storeInstance
}

func newRedisStore() (Store, error) {
	addr := getEnv("REDIS_ADDR", "")
	password := getEnv("REDIS_PASSWORD", "")
	passwordRequired := getEnv("REDIS_PASSWORD_REQUIRED", "true") == "true"

	if addr == "" {
		return nil, fmt.Errorf("REDIS_ADDR is required")
	}

	if passwordRequired && password == "" {
		return nil, fmt.Errorf("REDIS_PASSWORD is required when REDIS_PASSWORD_REQUIRED is true")
	}

	return redis.NewRedisStore(addr, password)
}

func newValkeyStore() (Store, error) {
	addr := getEnv("VALKEY_ADDR", "")
	password := getEnv("VALKEY_PASSWORD", "")
	passwordRequired := getEnv("VALKEY_PASSWORD_REQUIRED", "true") == "true"

	if addr == "" {
		addr = getEnv("REDIS_ADDR", "")
	}

	if addr == "" {
		return nil, fmt.Errorf("VALKEY_ADDR (or REDIS_ADDR) is required")
	}

	if passwordRequired && password == "" {
		password = getEnv("REDIS_PASSWORD", "")
	}

	if passwordRequired && password == "" {
		return nil, fmt.Errorf("VALKEY_PASSWORD (or REDIS_PASSWORD) is required when VALKEY_PASSWORD_REQUIRED is true")
	}

	return valkey.NewValkeyStore(addr, password)
}

func getEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

