package types

import (
	"fmt"
	"time"

	corev1 "k8s.io/api/core/v1"
)

const (
	SandboxKind          = "Sandbox"
	SandboxClaimsKind    = "SandboxClaim"
	AgentRuntimeKind     = "AgentRuntime"
	CodeInterpreterKind = "CodeInterpreter"
)

type SandboxInfo struct {
	SessionID     string              `json:"session_id"`
	Namespace     string              `json:"namespace"`
	Name          string              `json:"name"`
	Kind          string              `json:"kind"`
	EntryPoints   []SandboxEntryPoint `json:"entry_points"`
	PublicKey     string              `json:"public_key,omitempty"`
	CreatedAt     time.Time           `json:"created_at"`
	LastActivity  time.Time           `json:"last_activity"`
	IdentityToken string              `json:"identity_token,omitempty"`
}

type SandboxEntryPoint struct {
	Name      string `json:"name"`
	PathPrefix string `json:"path_prefix"`
	Port      int32  `json:"port"`
	Protocol  string `json:"protocol"`
}

type CreateSandboxRequest struct {
	Namespace    string              `json:"namespace"`
	Name         string              `json:"name"`
	Kind         string              `json:"kind"`
	Template     *SandboxTemplate    `json:"template,omitempty"`
	EntryPoints []SandboxEntryPoint `json:"entry_points"`
	PublicKey    string              `json:"public_key,omitempty"`
}

func (r *CreateSandboxRequest) Validate() error {
	if r.Namespace == "" {
		return fmt.Errorf("namespace is required")
	}
	if r.Name == "" {
		return fmt.Errorf("name is required")
	}
	if r.Kind == "" {
		return fmt.Errorf("kind is required")
	}
	if r.Kind != SandboxKind && r.Kind != SandboxClaimsKind {
		return fmt.Errorf("invalid kind: %s", r.Kind)
	}
	return nil
}

type CreateSandboxResponse struct {
	SessionID  string              `json:"session_id"`
	EntryPoints []SandboxEntryPoint `json:"entry_points"`
	Namespace  string              `json:"namespace"`
	Name       string              `json:"name"`
}

type SandboxTemplate struct {
	RuntimeClassName string            `json:"runtime_class_name,omitempty"`
	Image           string            `json:"image,omitempty"`
	ImagePullSecrets []string         `json:"image_pull_secrets,omitempty"`
	Environment     []corev1.EnvVar   `json:"environment,omitempty"`
	Resources       *corev1.ResourceRequirements `json:"resources,omitempty"`
}

package api

import "errors"

var (
	ErrAgentRuntimeNotFound    = errors.New("agent runtime not found")
	ErrCodeInterpreterNotFound = errors.New("code interpreter not found")
	ErrTemplateMissing         = errors.New("sandbox template missing")
	ErrPublicKeyMissing        = errors.New("public key missing")
)

type SessionNotFoundError struct {
	SessionID string
}

func (e *SessionNotFoundError) Error() string {
	return "session not found: " + e.SessionID
}

type SandboxTemplateNotFoundError struct {
	TemplateName string
}

func (e *SandboxTemplateNotFoundError) Error() string {
	return "sandbox template not found: " + e.TemplateName
}

type UpstreamUnavailableError struct {
	Message string
}

func (e *UpstreamUnavailableError) Error() string {
	return "upstream unavailable: " + e.Message
}

type InternalError struct {
	Message string
}

func (e *InternalError) Error() string {
	return "internal error: " + e.Message
}

package v1alpha1

import (
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/runtime/schema"
)

var (
	GroupVersion = schema.GroupVersion{Group: "runtime.agentcube.volcano.sh", Version: "v1alpha1"}

	SchemeBuilder = &scheme.Builder{GroupVersion: GroupVersion}

	AddToScheme = SchemeBuilder.AddToScheme
)

func init() {
	SchemeBuilder.Register(&AgentRuntime{}, &AgentRuntimeList{})
	SchemeBuilder.Register(&CodeInterpreter{}, &CodeInterpreterList{})
}

var (
	_ runtime.Object = (*AgentRuntime)(nil)
	_ runtime.Object = (*AgentRuntimeList)(nil)
	_ runtime.Object = (*CodeInterpreter)(nil)
	_ runtime.Object = (*CodeInterpreterList)(nil)
)

package v1alpha1

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
)

const (
	AgentRuntimeKind          = "AgentRuntime"
	AgentRuntimeListKind      = "AgentRuntimeList"
	CodeInterpreterKind       = "CodeInterpreter"
	CodeInterpreterListKind   = "CodeInterpreterList"
	AgentRuntimePlural        = "agentruntimes"
	CodeInterpreterPlural    = "codeinterpreters"
	AgentRuntimeCRDName       = AgentRuntimePlural + "." + GroupVersion.Group
	CodeInterpreterCRDName    = CodeInterpreterPlural + "." + GroupVersion.Group
)

func AgentRuntimeGVK() metav1.GroupVersionKind {
	return GroupVersion.WithKind(AgentRuntimeKind)
}

func CodeInterpreterGVK() metav1.GroupVersionKind {
	return GroupVersion.WithKind(CodeInterpreterKind)
}

