}

// +kubebuilder:object:root=true

type AgentRuntimeList struct {
	metav1.TypeMeta `json:",inline"`
	metav1.ListMeta `json:"metadata,omitempty"`
	Items           []AgentRuntime `json:"items"`
}

func (in *AgentRuntime) DeepCopyInto(out *AgentRuntime) {
	*out = *in
	out.TypeMeta = in.TypeMeta
	in.ObjectMeta.DeepCopyInto(&out.ObjectMeta)
	in.Spec.DeepCopyInto(&out.Spec)
	in.Status.DeepCopyInto(&out.Status)
}

func (in *AgentRuntime) DeepCopy() *AgentRuntime {
	if in == nil {
		return nil
	}
	out := new(AgentRuntime)
	in.DeepCopyInto(out)
	return out
}

func (in *AgentRuntimeList) DeepCopyInto(out *AgentRuntimeList) {
	*out = *in
	out.TypeMeta = in.TypeMeta
	in.ListMeta.DeepCopyInto(&out.ListMeta)
	if in.Items != nil {
		in.Items = make([]AgentRuntime, len(in.Items))
		copy(in.Items, out.Items)
	}
}

func (in *AgentRuntimeList) DeepCopy() *AgentRuntimeList {
	if in == nil {
		return nil
	}
	out := new(AgentRuntimeList)
	in.DeepCopyInto(out)
	return out
}

var _ runtime.Object = &AgentRuntime{}
var _ runtime.Object = &AgentRuntimeList{}

package v1alpha1

import (
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
)

// +kubebuilder:object:root=true
// +kubebuilder:subresource:status
// +kubebuilder:printcolumn:name="Age",type="date",JSONPath=".metadata.creationTimestamp"
// +kubebuilder:resource:scope=Namespaced

type CodeInterpreter struct {
	metav1.TypeMeta   `json:",inline"`
	metav1.ObjectMeta `json:"metadata,omitempty"`

	Spec   CodeInterpreterSpec   `json:"spec,omitempty"`
	Status CodeInterpreterStatus `json:"status,omitempty"`
}

type CodeInterpreterSpec struct {
	Ports               []TargetPort               `json:"ports,omitempty"`
	Template            *CodeInterpreterSandboxTemplate `json:"template,omitempty"`
	SessionTimeout      *metav1.Duration           `json:"session_timeout,omitempty"`
	MaxSessionDuration *metav1.Duration           `json:"max_session_duration,omitempty"`
	WarmPoolSize        *int32                     `json:"warm_pool_size,omitempty"`
	AuthMode            AuthModeType               `json:"auth_mode,omitempty"`
}

type CodeInterpreterSandboxTemplate struct {
	RuntimeClassName string            `json:"runtime_class_name,omitempty"`
	Image           string            `json:"image,omitempty"`
	ImagePullSecrets []string         `json:"image_pull_secrets,omitempty"`
	Environment     []EnvVar          `json:"environment,omitempty"`
	Resources       *ResourceRequirements `json:"resources,omitempty"`
