package workloadmanager

import "os"

type Config struct {
	Port              string
	RuntimeClassName  string
	EnableTLS         bool
	TLSCert           string
	TLSKey            string
	EnableAuth        bool
}

func LoadConfig() *Config {
	return &Config{
		Port:             getEnv("PORT", "8080"),
		RuntimeClassName: getEnv("RUNTIME_CLASS_NAME", ""),
		EnableTLS:        getEnv("ENABLE_TLS", "false") == "true",
		TLSCert:          getEnv("TLS_CERT", ""),
		TLSKey:           getEnv("TLS_KEY", ""),
		EnableAuth:       getEnv("ENABLE_AUTH", "false") == "true",
	}
}

func getEnv(key, defaultValue string) string {
	if value := os.Getenv(key); value != "" {
		return value
	}
	return defaultValue
}

package workloadmanager

import (
	"context"
	"fmt"
	"net/http"
	"os"
	"os/signal"
	"syscall"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/client-go/kubernetes"
	"k8s.io/client-go/tools/clientcmd"
	"k8s.io/klog/v2"
)

type Server struct {
	config             *Config
	engine             *gin.Engine
	httpServer         *http.Server
	k8sClient          *K8sClient
	sandboxController  *SandboxController
	tokenCache         *TokenCache
	informers          *InformerSet
	store              store.Store
}

func NewServer(config *Config) (*Server, error) {
	k8sClient, err := NewK8sClient()
	if err != nil {
		return nil, fmt.Errorf("failed to create k8s client: %w", err)
	}

	storeClient := store.Storage()

	svc := &Server{
		config:            config,
		engine:            gin.New(),
		k8sClient:         k8sClient,
		sandboxController: NewSandboxController(k8sClient),
		tokenCache:        NewTokenCache(1000, 5*time.Minute),
		informers:         NewInformerSet(k8sClient),
		store:             storeClient,
	}

	svc.setupRouter()
	return svc, nil
}

func (s *Server) setupRouter() {
	s.engine.Use(gin.Logger())
	s.engine.Use(gin.Recovery())

	s.engine.GET("/health", s.handleHealth)

	v1 := s.engine.Group("/v1")
	{
		if s.config.EnableAuth {
			v1.Use(s.authMiddleware())
		}

		v1.POST("/agent-runtime", s.handleAgentRuntimeCreate)
		v1.DELETE("/agent-runtime/:namespace/:name", s.handleAgentRuntimeDelete)
		v1.POST("/code-interpreter", s.handleCodeInterpreterCreate)
		v1.DELETE("/code-interpreter/:namespace/:name", s.handleCodeInterpreterDelete)
		v1.DELETE("/sandbox/:session_id", s.handleDeleteSandbox)
	}
}

func (s *Server) handleHealth(c *gin.Context) {
	c.JSON(http.StatusOK, gin.H{"status": "healthy"})
}

func (s *Server) Start() error {
	addr := fmt.Sprintf(":%s", s.config.Port)
	s.httpServer = &http.Server{
		Addr:    addr,
		Handler: s.engine,
	}

	klog.Infof("Starting workload manager on %s", addr)

	if s.config.EnableTLS {
		return s.httpServer.ListenAndServeTLS(s.config.TLSCert, s.config.TLSKey)
	}
	return s.httpServer.ListenAndServe()
}

func (s *Server) Shutdown(ctx context.Context) error {
	klog.Info("Shutting down workload manager")
	if s.httpServer != nil {
		return s.httpServer.Shutdown(ctx)
	}
	return nil
}

func (s *Server) RunUntilShutdown() error {
	stopCh := make(chan os.Signal, 1)
	signal.Notify(stopCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-stopCh
		klog.Info("Received shutdown signal")
		ctx, cancel := context.WithTimeout(context.Background(), 30*time.Second)
		defer cancel()
		s.Shutdown(ctx)
	}()

	return s.Start()
}

func (s *Server) authMiddleware() gin.HandlerFunc {
	return func(c *gin.Context) {
		authHeader := c.GetHeader("Authorization")
		if authHeader == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "missing authorization header"})
			return
		}

		token := authHeader[len("Bearer "):]
		if token == "" {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": "invalid authorization header"})
			return
		}

		if cached, found := s.tokenCache.Get(token); found {
			c.Set("service_account", cached.serviceAccount)
			c.Set("namespace", cached.namespace)
			c.Next()
			return
		}

		sa, namespace, err := s.validateServiceAccountToken(token)
		if err != nil {
			c.AbortWithStatusJSON(http.StatusUnauthorized, gin.H{"error": err.Error()})
			return
		}

		s.tokenCache.Set(token, &CachedToken{serviceAccount: sa, namespace: namespace})
		c.Set("service_account", sa)
		c.Set("namespace", namespace)
		c.Next()
	}
}

func (s *Server) validateServiceAccountToken(token string) (string, string, error) {
	return validateServiceAccountToken(s.k8sClient.clientset, token)
}

func buildRESTConfig() (*clientcmdapi.Config, error) {
	config, err := clientcmd.BuildConfigFromFlags("", "")
	if err != nil {
		return nil, err
	}
	config.QPS = 50
	config.Burst = 100
	return config, nil
}

func getKubernetesClientset() (*kubernetes.Clientset, error) {
	config, err := buildRESTConfig()
	if err != nil {
		return nil, err
	}
	return kubernetes.NewForConfig(config)
}

package workloadmanager

import (
	"encoding/json"
	"fmt"
	"net/http"

	"github.com/gin-gonic/gin"
	"github.com/volcano-sh/agentcube/pkg/api"
	"github.com/volcano-sh/agentcube/pkg/common/types"
	"sigs.k8s.io/controller-runtime/pkg/client"
)

type CreateAgentRuntimeRequest struct {
	Namespace string `json:"namespace" binding:"required"`
	Name     string `json:"name" binding:"required"`
	Spec     any    `json:"spec"`
}

type CreateCodeInterpreterRequest struct {
	Namespace string `json:"namespace" binding:"required"`
	Name     string `json:"name" binding:"required"`
	Spec     any    `json:"spec"`
}

func (s *Server) handleAgentRuntimeCreate(c *gin.Context) {
	var req CreateAgentRuntimeRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	namespace := c.GetString("namespace")
	if namespace == "" {
		namespace = req.Namespace
	}

	sandbox, err := s.sandboxController.CreateSandbox(c.Request.Context(), namespace, req.Name, types.AgentRuntimeKind, nil)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	sandboxInfo := &types.SandboxInfo{
		SessionID:    sandbox.SessionID,
		Namespace:    sandbox.Namespace,
		Name:         sandbox.Name,
		Kind:         types.AgentRuntimeKind,
		EntryPoints:  sandbox.EntryPoints,
		PublicKey:    sandbox.PublicKey,
		CreatedAt:    sandbox.CreatedAt,
		LastActivity: sandbox.CreatedAt,
	}

	if err := s.store.StoreSandbox(c.Request.Context(), sandboxInfo); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to store sandbox: %v", err)})
		return
	}

	resp := types.CreateSandboxResponse{
		SessionID:   sandbox.SessionID,
		EntryPoints: sandbox.EntryPoints,
		Namespace:   sandbox.Namespace,
		Name:        sandbox.Name,
	}

	c.JSON(http.StatusCreated, resp)
}

func (s *Server) handleAgentRuntimeDelete(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")

	if err := s.sandboxController.DeleteSandbox(c.Request.Context(), namespace, name); err != nil {
		if client.IsNotFound(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("agent runtime %s/%s not found", namespace, name)})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "deleted"})
}

func (s *Server) handleCodeInterpreterCreate(c *gin.Context) {
	var req CreateCodeInterpreterRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	namespace := c.GetString("namespace")
	if namespace == "" {
		namespace = req.Namespace
	}

	sandbox, err := s.sandboxController.CreateSandbox(c.Request.Context(), namespace, req.Name, types.CodeInterpreterKind, nil)
	if err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	sandboxInfo := &types.SandboxInfo{
		SessionID:    sandbox.SessionID,
		Namespace:    sandbox.Namespace,
		Name:         sandbox.Name,
		Kind:         types.CodeInterpreterKind,
		EntryPoints:  sandbox.EntryPoints,
		PublicKey:    sandbox.PublicKey,
		CreatedAt:    sandbox.CreatedAt,
		LastActivity: sandbox.CreatedAt,
	}

	if err := s.store.StoreSandbox(c.Request.Context(), sandboxInfo); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": fmt.Sprintf("failed to store sandbox: %v", err)})
		return
	}

	resp := types.CreateSandboxResponse{
		SessionID:   sandbox.SessionID,
		EntryPoints: sandbox.EntryPoints,
		Namespace:   sandbox.Namespace,
		Name:        sandbox.Name,
	}

	c.JSON(http.StatusCreated, resp)
}

func (s *Server) handleCodeInterpreterDelete(c *gin.Context) {
	namespace := c.Param("namespace")
	name := c.Param("name")

	if err := s.sandboxController.DeleteSandbox(c.Request.Context(), namespace, name); err != nil {
		if client.IsNotFound(err) {
			c.JSON(http.StatusNotFound, gin.H{"error": fmt.Sprintf("code interpreter %s/%s not found", namespace, name)})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "deleted"})
}

func (s *Server) handleDeleteSandbox(c *gin.Context) {
	sessionID := c.Param("session_id")

	sandboxInfo, err := s.store.GetSandboxBySessionID(c.Request.Context(), sessionID)
	if err != nil {
		if err == api.ErrNotFound {
			c.JSON(http.StatusNotFound, gin.H{"error": "session not found"})
			return
		}
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	if err := s.sandboxController.DeleteSandbox(c.Request.Context(), sandboxInfo.Namespace, sandboxInfo.Name); err != nil {
		if !client.IsNotFound(err) {
			c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
			return
		}
	}

	if err := s.store.DeleteSandboxBySessionID(c.Request.Context(), sessionID); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, gin.H{"message": "deleted"})
}

func sendError(c *gin.Context, code int, message string) {
	c.JSON(code, gin.H{"error": message})
}

func sendErrorJSON(c *gin.Context, code int, err error) {
	c.JSON(code, gin.H{"error": err.Error()})
}

func (s *Server) parseRequestBody(c *gin.Context, v any) error {
	body, err := c.GetRawData()
	if err != nil {
		return err
	}
	return json.Unmarshal(body, v)
}

