	"k8s.io/client-go/tools/cache"
)

type InformerSet struct {
	factory informers.SharedInformerFactory
}

var (
	AgentRuntimeGVR = schema.GroupVersionResource{
		Group:    "runtime.agentcube.volcano.sh",
		Version:  "v1alpha1",
		Resource: "agentruntimes",
	}
	CodeInterpreterGVR = schema.GroupVersionResource{
		Group:    "runtime.agentcube.volcano.sh",
		Version:  "v1alpha1",
		Resource: "codeinterpreters",
	}
	SandboxGVR = schema.GroupVersionResource{
		Group:    "agent.sandbox.volcano.sh",
		Version:  "v1alpha1",
		Resource: "sandboxes",
	}
	SandboxClaimGVR = schema.GroupVersionResource{
		Group:    "agent.sandbox.volcano.sh",
		Version:  "v1alpha1",
		Resource: "sandboxclaims",
	}
)

func NewInformerSet(k8sClient *K8sClient) *InformerSet {
	factory := informers.NewSharedInformerFactory(k8sClient.clientset, 30*time.Second)
	return &InformerSet{
		factory: factory,
	}
}

func (i *InformerSet) Start(stopCh <-chan struct{}) error {
	i.factory.Start(stopCh)
	i.factory.WaitForCacheSync(stopCh)
	return nil
}

func (i *InformerSet) AgentRuntimeInformer() cache.SharedIndexInformer {
	return i.factory.Rbac().V1().ClusterRoles().Informer()
}

func (i *InformerSet) CodeInterpreterInformer() cache.SharedIndexInformer {
	return i.factory.Rbac().V1().ClusterRoles().Informer()
}

func (i *InformerSet) SandboxInformer() cache.SharedIndexInformer {
	return i.factory.Core().V1().Pods().Informer()
}

func (i *InformerSet) GetAgentRuntimeInformer() cache.SharedIndexInformer {
	return i.factory.Apps().V1().Deployments().Informer()
}

func (i *InformerSet) GetCodeInterpreterInformer() cache.SharedIndexInformer {
	return i.factory.Apps().V1().Deployments().Informer()
}

func GetGVR(kind string) (schema.GroupVersionResource, error) {
	switch kind {
	case "AgentRuntime":
