package workloadmanager

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/volcano-sh/agentcube/pkg/common/types"
	corev1 "k8s.io/api/core/v1"
	"k8s.io/apimachinery/pkg/api/errors"
	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/types"
	"k8s.io/client-go/util/workqueue"
	"k8s.io/klog/v2"
	"sigs.k8s.io/controller-runtime/pkg/client"
	"sigs.k8s.io/controller-runtime/pkg/controller"
	"sigs.k8s.io/controller-runtime/pkg/handler"
	"sigs.k8s.io/controller-runtime/pkg/manager"
	"sigs.k8s.io/controller-runtime/pkg/reconcile"
)

type SandboxController struct {
	k8sClient *K8sClient
	watchers  map[string]*Watcher
}

func NewSandboxController(k8sClient *K8sClient) *SandboxController {
	return &SandboxController{
		k8sClient: k8sClient,
		watchers:  make(map[string]*Watcher),
	}
}

func (s *SandboxController) CreateSandbox(ctx context.Context, namespace, name, kind string, template *types.SandboxTemplate) (*types.CreateSandboxResponse, error) {
	sessionID := generateSessionID()
	entryPoints := []types.SandboxEntryPoint{
		{
			Name:       "default",
			PathPrefix: "/",
			Port:       8080,
			Protocol:   "HTTP",
		},
	}

	publicKey := generateRSAKeyPair()

	sandboxObj := s.buildSandboxObject(namespace, name, kind, sessionID, template)

	if err := s.k8sClient.clientset.AppsV1().Deployments(namespace).Create(ctx, sandboxObj, metav1.CreateOptions{}); err != nil {
		return nil, fmt.Errorf("failed to create deployment: %w", err)
	}

	watcher := NewWatcher(sessionID)
	s.watchers[sessionID] = watcher

	if err := watcher.WaitForRunning(ctx, 2*time.Minute); err != nil {
		return nil, fmt.Errorf("sandbox not ready: %w", err)
	}

	return &types.CreateSandboxResponse{
		SessionID:   sessionID,
		EntryPoints: entryPoints,
		Namespace:   namespace,
		Name:        name,
	}, nil
}

func (s *SandboxController) DeleteSandbox(ctx context.Context, namespace, name string) error {
	deploymentName := strings.ReplaceAll(name, "/", "-")

	err := s.k8sClient.clientset.AppsV1().Deployments(namespace).Delete(ctx, deploymentName, metav1.DeleteOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return nil
		}
		return err
	}

	return nil
}

func (s *SandboxController) buildSandboxObject(namespace, name, kind, sessionID string, template *types.SandboxTemplate) *corev1.Pod {
	labels := map[string]string{
		"app":                          "agentcube",
		"agentcube-runtime":           kind,
		"agentcube-session-id":        sessionID,
	}

	pod := &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      name,
			Namespace: namespace,
			Labels:    labels,
		},
		Spec: corev1.PodSpec{
			Containers: []corev1.Container{
				{
					Name:  "picod",
					Image: "agentcube/picod:latest",
					Ports: []corev1.ContainerPort{
						{
							ContainerPort: 8080,
						},
					},
				},
			},
		},
	}

	return pod
}

func generateSessionID() string {
	return fmt.Sprintf("sess-%d", time.Now().UnixNano())
}

func generateRSAKeyPair() string {
	return "public-key-placeholder"
}

func (sc *SandboxController) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	name := req.Name
	namespace := req.Namespace

	klog.Infof("Reconciling sandbox %s/%s", namespace, name)

	deployment, err := sc.k8sClient.clientset.AppsV1().Deployments(namespace).Get(ctx, name, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return reconcile.Result{}, nil
		}
		return reconcile.Result{}, err
	}

	if deployment.Status.ReadyReplicas > 0 {
		if watcher, exists := sc.watchers[deployment.Name]; exists {
			watcher.MarkRunning()
		}
	}

	return reconcile.Result{}, nil
}

func (sc *SandboxController) InjectClient(c client.Client) error {
	return nil
}

func (sc *SandboxController) SetupWithManager(mgr manager.Manager) error {
	c, err := controller.New("sandbox-controller", mgr, controller.Options{
		Reconciler: sc,
	})
	if err != nil {
		return err
	}

	return c.Watch(&source.Kind{Type: &corev1.Pod{}}, &handler.EnqueueRequestForObject{})
}

type sandboxReconciler struct {
	client client.Client
	scheme *runtime.Scheme
}

func (r *sandboxReconciler) Reconcile(ctx context.Context, req reconcile.Request) (reconcile.Result, error) {
	return reconcile.Result{}, nil
}

