func NewSandboxBuilder() *SandboxBuilder {
	return &SandboxBuilder{}
}

func (b *SandboxBuilder) BuildSandboxObject(namespace, name, kind, sessionID string, template *agentcubetypes.SandboxTemplate) *corev1.Pod {
	labels := map[string]string{
		"app":                   "agentcube",
		"agentcube-runtime":    kind,
		"agentcube-session-id": sessionID,
	}

	annotations := map[string]string{
		"agentcube-session-id": sessionID,
	}

	podSpec := corev1.PodSpec{
		RestartPolicy: corev1.RestartPolicyAlways,
		Containers: []corev1.Container{
			{
				Name:  "sandbox",
				Image: getDefaultImage(template),
				Env:   buildEnvVars(template),
			},
		},
	}

	if template != nil && template.RuntimeClassName != "" {
		podSpec.RuntimeClassName = &template.RuntimeClassName
	}

	if template != nil && len(template.ImagePullSecrets) > 0 {
		podSpec.ImagePullSecrets = buildImagePullSecrets(template.ImagePullSecrets)
	}

	return &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:        name,
			Namespace:   namespace,
			Labels:      labels,
			Annotations: annotations,
		},
		Spec: podSpec,
	}
}

func (b *SandboxBuilder) BuildSandboxClaim(namespace, name, sessionID string) *corev1.Pod {
	labels := map[string]string{
		"app":                   "agentcube",
		"agentcube-session-id": sessionID,
	}

	return &corev1.Pod{
		ObjectMeta: metav1.ObjectMeta{
			Name:      name + "-claim",
			Namespace: namespace,
			Labels:    labels,
		},
		Spec: corev1.PodSpec{
			RestartPolicy: corev1.RestartPolicyNever,
			Containers: []corev1.Container{
				{
					Name:  "claim",
					Image: "agentcube/picod:latest",
				},
			},
		},
	}
}

func getDefaultImage(template *agentcubetypes.SandboxTemplate) string {
	if template != nil && template.Image != "" {
		return template.Image
	}
	return "agentcube/picod:latest"
}

func buildEnvVars(template *agentcubetypes.SandboxTemplate) []corev1.EnvVar {
	if template == nil {
		return nil
	}

	envVars := make([]corev1.EnvVar, len(template.Environment))
	for i, env := range template.Environment {
		envVars[i] = corev1.EnvVar{
			Name:  env.Name,
			Value: env.Value,
		}
	}

	return envVars
}

func buildImagePullSecrets(secrets []string) []corev1.LocalObjectReference {
	result := make([]corev1.LocalObjectReference, len(secrets))
	for i, secret := range secrets {
		result[i] = corev1.LocalObjectReference{Name: secret}
	}
	return result
}

func sanitizeName(name string) string {
	return strings.ReplaceAll(name, "/", "-")
}

package workloadmanager

import (
	"context"
	"time"

	"github.com/volcano-sh/agentcube/pkg/store"
	"k8s.io/klog/v2"
)

type GarbageCollector struct {
	store        store.Store
	k8sClient    *K8sClient
	stopCh       <-chan struct{}
	ticker       *time.Ticker
	inactiveCutoff time.Duration
	expiredBatchSize int64
	inactiveBatchSize int64
}

func NewGarbageCollector(store store.Store, k8sClient *K8sClient, stopCh <-chan struct{}) *GarbageCollector {
	return &GarbageCollector{
		store:            store,
		k8sClient:        k8sClient,
		stopCh:           stopCh,
		ticker:           time.NewTicker(15 * time.Second),
		inactiveCutoff:  15 * time.Minute,
		expiredBatchSize: 16,
		inactiveBatchSize: 16,
	}
}

func (gc *GarbageCollector) Start() {
	klog.Info("Starting garbage collector")

	for {
		select {
		case <-gc.stopCh:
			gc.ticker.Stop()
			klog.Info("Garbage collector stopped")
			return
		case <-gc.ticker.C:
			gc.collect()
		}
	}
}

func (gc *GarbageCollector) collect() {
	ctx := context.Background()

	now := time.Now()
	inactiveBefore := now.Add(-gc.inactiveCutoff)

	if err := gc.cleanupInactive(ctx, inactiveBefore); err != nil {
		klog.Errorf("Failed to cleanup inactive sandboxes: %v", err)
	}

	if err := gc.cleanupExpired(ctx, now); err != nil {
		klog.Errorf("Failed to cleanup expired sandboxes: %v", err)
	}
}

func (gc *GarbageCollector) cleanupInactive(ctx context.Context, before time.Time) error {
	sandboxes, err := gc.store.ListInactiveSandboxes(ctx, before, gc.inactiveBatchSize)
	if err != nil {
		return err
	}

	for _, sandbox := range sandboxes {
		klog.Infof("Deleting inactive sandbox: %s", sandbox.SessionID)
		if err := gc.k8sClient.clientset.AppsV1().Deployments(sandbox.Namespace).Delete(ctx, sandbox.Name, nil); err != nil {
			klog.Errorf("Failed to delete sandbox %s: %v", sandbox.Name, err)
			continue
		}

		if err := gc.store.DeleteSandboxBySessionID(ctx, sandbox.SessionID); err != nil {
			klog.Errorf("Failed to remove sandbox from store: %v", err)
		}
	}

	return nil
}

func (gc *GarbageCollector) cleanupExpired(ctx context.Context, now time.Time) error {
	sandboxes, err := gc.store.ListExpiredSandboxes(ctx, now, gc.expiredBatchSize)
	if err != nil {
		return err
	}

	for _, sandbox := range sandboxes {
		klog.Infof("Deleting expired sandbox: %s", sandbox.SessionID)
		if err := gc.k8sClient.clientset.AppsV1().Deployments(sandbox.Namespace).Delete(ctx, sandbox.Name, nil); err != nil {
			klog.Errorf("Failed to delete sandbox %s: %v", sandbox.Name, err)
			continue
		}

		if err := gc.store.DeleteSandboxBySessionID(ctx, sandbox.SessionID); err != nil {
			klog.Errorf("Failed to remove sandbox from store: %v", err)
		}
	}

	return nil
}

