	"time"

	"k8s.io/klog/v2"
)

type Watcher struct {
	sessionID string
	readyCh   chan struct{}
	running   bool
	timeout   time.Duration
}

func NewWatcher(sessionID string) *Watcher {
	return &Watcher{
		sessionID: sessionID,
		readyCh:   make(chan struct{}),
		running:   false,
		timeout:   2 * time.Minute,
	}
}

func (w *Watcher) WaitForRunning(ctx context.Context, timeout time.Duration) error {
	w.timeout = timeout

	select {
	case <-w.readyCh:
		klog.Infof("Sandbox %s is running", w.sessionID)
		return nil
	case <-ctx.Done():
		return ctx.Err()
	case <-time.After(w.timeout):
		return fmt.Errorf("timeout waiting for sandbox %s to start", w.sessionID)
	}
}

func (w *Watcher) MarkRunning() {
	if !w.running {
		w.running = true
		close(w.readyCh)
	}
}

func (w *Watcher) IsRunning() bool {
	return w.running
}

func (w *Watcher) GetSessionID() string {
	return w.sessionID
}

