)

type PodResolver struct {
	clientset *kubernetes.Clientset
}

func NewPodResolver(clientset *kubernetes.Clientset) *PodResolver {
	return &PodResolver{
		clientset: clientset,
	}
}

func (r *PodResolver) ResolvePodIP(ctx context.Context, namespace, podName string, sessionID string) (string, error) {
	pod, err := r.clientset.CoreV1().Pods(namespace).Get(ctx, podName, metav1.GetOptions{})
	if err != nil {
		if errors.IsNotFound(err) {
			return r.resolveViaLabelSelector(ctx, namespace, sessionID)
		}
		return "", err
	}

	if !r.isPodReady(pod) {
		return "", fmt.Errorf("pod %s is not ready", podName)
	}

	if pod.Status.PodIP == "" {
		return "", fmt.Errorf("pod %s has no IP address", podName)
	}

	return pod.Status.PodIP, nil
}

func (r *PodResolver) resolveViaLabelSelector(ctx context.Context, namespace, sessionID string) (string, error) {
	selector := labels.SelectorFromSet(labels.Set{
		"agentcube-session-id": sessionID,
	})

	pods, err := r.clientset.CoreV1().Pods(namespace).List(ctx, metav1.ListOptions{
		LabelSelector: selector.String(),
	})
	if err != nil {
		return "", err
	}

	for _, pod := range pods.Items {
		if r.isPodReady(&pod) && pod.Status.PodIP != "" {
			return pod.Status.PodIP, nil
		}
	}

	return "", fmt.Errorf("no running pod found for session %s", sessionID)
}

func (r *PodResolver) isPodReady(pod *corev1.Pod) bool {
	for _, condition := range pod.Status.Conditions {
		if condition.Type == corev1.PodReady && condition.Status == corev1.ConditionTrue {
			return true
		}
	}
	return false
}

func (r *PodResolver) GetPodBySessionID(ctx context.Context, namespace, sessionID string) (*corev1.Pod, error) {
	pod, err := r.resolveViaLabelSelectorGet(ctx, namespace, sessionID)
	if err != nil {
		return nil, err
	}
	return pod, nil
}

func (r *PodResolver) resolveViaLabelSelectorGet(ctx context.Context, namespace, sessionID string) (*corev1.Pod, error) {
	selector := labels.SelectorFromSet(labels.Set{
		"agentcube-session-id": sessionID,
	})

	pods, err := r.clientset.CoreV1().Pods(namespace).List(ctx, metav1.ListOptions{
		LabelSelector: selector.String(),
	})
	if err != nil {
		return nil, err
	}

	if len(pods.Items) == 0 {
		return nil, fmt.Errorf("no pod found for session %s", sessionID)
	}

	return &pods.Items[0], nil
}

