import (
	"flag"
	"os"
	"os/signal"
	"syscall"

	"github.com/volcano-sh/agentcube/pkg/workloadmanager"
	"k8s.io/klog/v2"
)

func main() {
	klog.InitFlags(flag.CommandLine)
	flag.Parse()

	port := flag.String("port", "8080", "Port to listen on")
	runtimeClassName := flag.String("runtime-class-name", "", "Runtime class name for pods")
	enableTLS := flag.Bool("enable-tls", false, "Enable TLS")
	tlsCert := flag.String("tls-cert", "", "TLS certificate file")
	tlsKey := flag.String("tls-key", "", "TLS key file")
	enableAuth := flag.Bool("enable-auth", false, "Enable authentication")

	config := workloadmanager.LoadConfig()
	if *port != "" {
		config.Port = *port
	}
	if *runtimeClassName != "" {
		config.RuntimeClassName = *runtimeClassName
	}
	config.EnableTLS = *enableTLS
	if *tlsCert != "" {
		config.TLSCert = *tlsCert
	}
	if *tlsKey != "" {
		config.TLSKey = *tlsKey
	}
	config.EnableAuth = *enableAuth

	server, err := workloadmanager.NewServer(config)
	if err != nil {
		klog.Exitf("Failed to create server: %v", err)
	}

	stopCh := make(chan os.Signal, 1)
	signal.Notify(stopCh, syscall.SIGINT, syscall.SIGTERM)

	go func() {
		<-stopCh
		klog.Info("Shutting down...")
		server.Shutdown(nil)
	}()

	if err := server.Start(); err != nil {
		klog.Exitf("Server error: %v", err)
	}
}

