func (m *manager) GetSession(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	return m.storeClient.GetSandboxBySessionID(ctx, sessionID)
}

func (m *manager) CreateSession(ctx context.Context, namespace, name, kind string) (*types.CreateSandboxResponse, error) {
	url := fmt.Sprintf("%s/v1/%s", m.workloadMgrAddr, getKindEndpoint(kind))

	reqBody := map[string]string{
		"namespace": namespace,
		"name":      name,
	}
	_, _ = json.Marshal(reqBody)

	req, err := http.NewRequestWithContext(ctx, "POST", url, nil)
	if err != nil {
		return nil, err
	}

	resp, err := m.httpClient.Do(req)
	if err != nil {
		return nil, err
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusCreated {
		return nil, fmt.Errorf("failed to create session: %d", resp.StatusCode)
	}

	var result types.CreateSandboxResponse
	if err := json.NewDecoder(resp.Body).Decode(&result); err != nil {
		return nil, err
	}

	return &result, nil
}

func (m *manager) DeleteSession(ctx context.Context, sessionID string) error {
	url := fmt.Sprintf("%s/v1/sandbox/%s", m.workloadMgrAddr, sessionID)

	req, err := http.NewRequestWithContext(ctx, "DELETE", url, nil)
	if err != nil {
		return err
	}

	_, err = m.httpClient.Do(req)
	if err != nil {
		return err
	}

	return m.storeClient.DeleteSandboxBySessionID(ctx, sessionID)
}

func (m *manager) UpdateLastActivity(ctx context.Context, sessionID string) error {
	return m.storeClient.UpdateSessionLastActivity(ctx, sessionID, time.Now())
}

func getKindEndpoint(kind string) string {
	switch kind {
	case "AgentRuntime":
		return "agent-runtime"
	case "CodeInterpreter":
		return "code-interpreter"
	default:
		return "agent-runtime"
	}
}

